  const [fileName, setFileName] = useState("")
  const [sheetName, setSheetName] = useState("")
  const [isDragging, setIsDragging] = useState(false)
  const [isCreating, setIsCreating] = useState(false)

  // ── File handling ──
  const handleFile = useCallback(async (file: File) => {
    if (!file) return
    setFileName(file.name)
    const baseName = file.name.replace(/\.(csv|xlsx|xls|txt)$/i, "")
    setSheetName(baseName)
    try {
      const parsed = await parseFile(file)
      setCsvData(parsed)
    } catch {
      alert("Could not parse file. Please use CSV or Excel format.")
    }
  }, [])

  const handleDrop = useCallback(
    (e: React.DragEvent) => {
      e.preventDefault()
      setIsDragging(false)
      const file = e.dataTransfer.files[0]
      if (file) handleFile(file)
    },
    [handleFile]
  )

  const handleStartEnrich = () => {
    if (!csvData) return
    setIsCreating(true)
    // Persist data for post-auth pickup
    localStorage.setItem(
      "pendingImport",
      JSON.stringify({ csvData, sheetName: sheetName || "Untitled Sheet" })
    )
    router.push("/register?intent=import")
  }

  const scrollToImport = () => {
    importSectionRef.current?.scrollIntoView({ behavior: "smooth" })
  }

